import torch
import copy
import numpy as np
import datasets
import collections
from sklearn.model_selection import train_test_split

class LFW(torch.utils.data.Dataset):

	def __init__(self, dataset, label2idx=None, retrieve_ids=None, transform=None, processor=None, seed=2025, test_size=0.2, exclude_labels=None, train=True):
		if train: assert label2idx is not None
		self.samples, self.labels = dataset["image"], [self.class_names[label] for label in dataset["class_name"]]
		train_samples, test_samples, train_labels, test_labels = train_test_split(self.samples, self.labels, test_size=test_size, random_state=seed, stratify=self.labels)
		(self.samples, self.labels) = (train_samples, train_labels) if train else (test_samples, test_labels)
		self.label2idx = label2idx if label2idx else {j:i for i,j in enumerate(set(self.labels))}
		self.idx2label = {v: k for k, v in self.label2idx.items()}
		if not train: self._label2idx = copy.deepcopy(self.label2idx)
		self.labels = [self.label2idx[i] for i in self.labels]

		# Retrieve specific IDs
		if retrieve_ids:
			retrieve_ids = {retrieve_ids} if isinstance(retrieve_ids, int) else set(retrieve_ids)
			filtered = [(s, l) for s, l in zip(self.samples, self.labels) if l in retrieve_ids]
			if filtered:
				self.samples, self.labels = zip(*filtered)
			else:
				self.samples, self.labels = [], []

		# Exclude specific labels while keeping old mappings
		if exclude_labels:
			exclude_labels = {self.idx2label[exclude_labels]} if isinstance(exclude_labels, int) else set(self.idx2label[e] for e in exclude_labels)
			self.label2idx = {l:i for i,l in enumerate(l for l in (self._label2idx if not train else self.label2idx) if l not in exclude_labels)}
			filtered = [(s,l) for s,l in zip(self.samples,[self.idx2label[i] for i in self.labels]) if l not in exclude_labels]
			if filtered:
				self.samples, self.labels = zip(*filtered)
				self.labels = [self.label2idx[i] for i in self.labels]
			else:
				self.samples, self.labels  = [], []
		self.data_processor = processor
		self.transform = transform

	def __len__(self):
		return len(self.samples)

	def __getitem__(self, idx):
		x = self.samples[idx]
		if self.data_processor:
			x = self.data_processor(images=x, return_tensors="pt")['pixel_values'].squeeze(0)
		if self.transform:
			x = self.transform(x)
		return x, self.labels[idx]

	@property
	def num_classes(self):
		return len(self.label2idx)

	@property
	def name(self):
		return "lfw"

