def load_lfw(processor_fn, num_clients=None, min_samples_per_class=32, batch_size=16, seed=2025, centralized=False, device='cuda', exclude_cids=None, partitions=None, **kwargs):

	data = datasets.load_dataset("bitmind/lfw", split='train').map(lambda x: {"class_name": "_".join(x["filename"].split("_")[:-1])})
	_cls = {cls for cls, count in collections.Counter(data["class_name"]).items() if count >= min_samples_per_class}
	data = data.filter(lambda x: x["class_name"] in _cls)

	########################################################
	exclude_labels = [i for s in [partitions[c] for c in exclude_cids] for i in s] if (exclude_cids and partitions) else None
	test_ds = LFW(dataset=data, train=False, processor=processor_fn(train=False), seed=seed, exclude_labels=exclude_labels)
	label2idx, num_classes = test_ds._label2idx, test_ds.num_classes
	test_ds = torch.utils.data.DataLoader(test_ds, batch_size=8*batch_size, shuffle=False, num_workers=8, pin_memory=True, persistent_workers=False, pin_memory_device=device)
	########################################################

	########################################################
	if centralized:
		train_ds = torch.utils.data.DataLoader(batch_size=4*batch_size, shuffle=True, num_workers=8, pin_memory=True, persistent_workers=False, pin_memory_device=device,
			dataset=LFW(dataset=data, train=True, retrieve_ids=None, label2idx=label2idx, processor=processor_fn(train=True), seed=seed, exclude_labels=exclude_labels)
		)
	else:
		assert num_clients is not None
		assert num_clients <= len(label2idx), "Number of clients cannot exceed the number of partitions."
		cid_ids = [list(p) for p in np.array_split(list(range(len(label2idx))), num_clients)] if partitions is None else partitions

		train_ds = []
		for cid in range(num_clients):
			cid_data = LFW(dataset=data, train=True, retrieve_ids=cid_ids[cid], label2idx=label2idx, processor=processor_fn(train=False), seed=seed, exclude_labels=exclude_labels)
			train_ds.append(torch.utils.data.DataLoader(batch_size=batch_size, shuffle=True, num_workers=8, pin_memory=True, persistent_workers=False, pin_memory_device=device, dataset=cid_data) if len(cid_data)>0 else None)
	########################################################

	return train_ds, test_ds, num_classes

